const state={lang:localStorage.getItem('tp-lang')||'ar',mode:localStorage.getItem('tp-mode')||'dark',theme:localStorage.getItem('tp-theme')||'purple',done:JSON.parse(localStorage.getItem('tp-done')||'[]'),favorites:JSON.parse(localStorage.getItem('tp-favorites')||'[]'),notes:JSON.parse(localStorage.getItem('tp-notes')||'{}'),fontSize:localStorage.getItem('tp-fontsize')||'md',reducedMotion:localStorage.getItem('tp-reduced')==='1',quizScores:JSON.parse(localStorage.getItem('tp-quiz-scores')||'{}')};
const ui={ar:{brand:'مسار التقنية',home:'الرئيسية',lessons:'الدروس',examples:'الأمثلة',quiz:'الاختبار',glossary:'المصطلحات',progress:'تقدمي',settings:'الإعدادات'},en:{brand:'Tech Path',home:'Home',lessons:'Lessons',examples:'Examples',quiz:'Quiz',glossary:'Glossary',progress:'Progress',settings:'Settings'}};
const lessons=[
{id:'srs',icon:'📄',ar:'وثيقة متطلبات النظام SRS',en:'Software Requirements Specification',descAr:'ابدأ المشروع بفهم المشكلة وتوثيق ما يحتاجه المستخدم قبل كتابة أي كود.',descEn:'Start by understanding the problem and documenting user needs before writing code.',objectives:['فهم معنى SRS','تمييز المتطلبات الوظيفية','تحويل النص إلى عناصر نظام'],storyAr:'تخيل أن عميلاً طلب نظام مكتبة وقال فقط: أريد إدارة الكتب. هذه الجملة غير كافية. وثيقة SRS تحول الفكرة العامة إلى متطلبات واضحة مثل إضافة كتاب، استعارة كتاب، وإرجاعه.',storyEn:'Imagine a client asks for a library system and only says: “manage books.” That is not enough. An SRS converts the idea into clear requirements such as adding, borrowing, and returning books.',sections:[['ما هي SRS؟','هي وثيقة تصف ما الذي يجب أن يفعله النظام، ومن سيستخدمه، وما القيود الموجودة. تركز على المطلوب وليس طريقة البرمجة.','It is a document that describes what the system must do, who will use it, and its constraints. It focuses on what is required, not how to code it.'],['أقسام مهمة','المقدمة، نطاق النظام، المستخدمون، المتطلبات الوظيفية، المتطلبات غير الوظيفية، القيود، وحالات الاستخدام.','Introduction, scope, users, functional requirements, non-functional requirements, constraints, and use cases.'],['مثال مبتدئ','متطلب وظيفي: يجب أن يستطيع الموظف إضافة كتاب. متطلب غير وظيفي: يجب أن تظهر نتيجة البحث خلال ثانيتين.','Functional: The employee shall add a book. Non-functional: Search results should appear within two seconds.']]},
{id:'database',icon:'🗄️',ar:'مقدمة إلى قواعد البيانات',en:'Introduction to Databases',descAr:'افهم لماذا نخزن البيانات داخل نظام منظم بدل الملفات المتفرقة.',descEn:'Understand why data is stored in an organized system instead of scattered files.',objectives:['Database وDBMS','RDBMS','الجداول والسجلات'],storyAr:'لو خزنت بيانات الطلاب في ملفات كثيرة، سيصعب البحث والتعديل ومنع التكرار. قاعدة البيانات تجمعها في مكان منظم وآمن.',storyEn:'If student data is stored in many files, searching, updating, and preventing duplication becomes difficult. A database keeps it organized and secure.',sections:[['قاعدة البيانات','مجموعة منظمة من البيانات يمكن البحث فيها وإضافتها وتعديلها وحذفها.','An organized collection of data that can be searched, inserted, updated, and deleted.'],['DBMS وRDBMS','DBMS هو البرنامج الذي يدير البيانات. RDBMS يخزن البيانات في جداول مرتبطة مثل Oracle وMySQL وPostgreSQL.','A DBMS manages data. An RDBMS stores data in related tables, such as Oracle, MySQL, and PostgreSQL.'],['مكونات الجدول','العمود يصف نوع المعلومة، والصف يمثل سجلًا واحدًا. مثال: جدول STUDENTS يحتوي Student_ID وName وGPA.','A column describes a data item, while a row represents one record.']]},
{id:'sql-nosql',icon:'⚖️',ar:'SQL وNoSQL',en:'SQL vs NoSQL',descAr:'تعرف على نوعي قواعد البيانات ومتى تختار كل واحد.',descEn:'Learn the two database families and when to choose each.',objectives:['SQL','NoSQL','اختيار النوع المناسب'],storyAr:'نظام الجامعة يحتاج علاقات واضحة بين الطلاب والمقررات، لذلك SQL مناسب. تطبيق منشورات مرن وسريع التغير قد يناسبه NoSQL.',storyEn:'A university system needs clear relationships between students and courses, so SQL fits. A flexible social feed may fit NoSQL.',sections:[['SQL','قواعد بيانات جدولية تعتمد على Schema وعلاقات وأوامر SQL. ممتازة للبيانات المنظمة والمعاملات الدقيقة.','Table-based databases with schemas, relationships, and SQL. Excellent for structured data and precise transactions.'],['NoSQL','يشمل Document وKey-Value وGraph وColumn stores. مناسب للبيانات المرنة أو التوسع الكبير.','Includes document, key-value, graph, and column stores. Useful for flexible data or large-scale growth.'],['الاختيار','اختر SQL عند وجود علاقات ومعاملات مهمة. اختر NoSQL عندما تتغير بنية البيانات كثيرًا أو تحتاج توسعًا أفقيًا واسعًا.','Choose SQL for relationships and important transactions. Choose NoSQL for frequently changing structures or broad horizontal scaling.']]},
{id:'erd',icon:'🧩',ar:'ERD',en:'Entity Relationship Diagram',descAr:'حوّل المتطلبات إلى كيانات وخصائص وعلاقات مرئية.',descEn:'Turn requirements into visual entities, attributes, and relationships.',objectives:['Entity وAttribute','PK وFK','Cardinality'],storyAr:'من SRS المكتبة نستخرج Book وMember وBorrow ككيانات، ثم نحدد الخصائص والعلاقات بينها.',storyEn:'From the library SRS, we extract Book, Member, and Borrow as entities, then define their attributes and relationships.',sections:[['الكيان والخاصية','الكيان شيء نخزن عنه بيانات مثل Student. الخاصية معلومة عنه مثل Name وGPA.','An entity is something we store data about, such as Student. An attribute is information about it, such as Name and GPA.'],['المفاتيح','Primary Key يميز كل سجل ولا يتكرر. Foreign Key يربط جدولًا بجدول آخر.','A primary key uniquely identifies each record. A foreign key connects one table to another.'],['العلاقات','1:1 واحد لواحد، 1:N واحد لمتعدد، M:N متعدد لمتعدد وتحتاج غالبًا جدولًا وسيطًا.','1:1 one-to-one, 1:N one-to-many, and M:N many-to-many, which usually needs a bridge table.']]},
{id:'schema',icon:'🧱',ar:'تحويل ERD إلى Schema',en:'ERD to Schema',descAr:'حوّل الرسم إلى جداول وأعمدة ومفاتيح قابلة للتنفيذ.',descEn:'Convert the diagram into executable tables, columns, and keys.',objectives:['تحويل الكيانات','تحويل العلاقات','إنشاء جدول وسيط'],storyAr:'كل كيان قوي يصبح جدولًا. علاقة 1:N تضع مفتاح جهة الواحد داخل جدول جهة المتعدد. علاقة M:N تنشئ جدولًا وسيطًا.',storyEn:'Each strong entity becomes a table. In 1:N, the key from the one side moves to the many side. M:N creates a bridge table.',sections:[['قاعدة التحويل','Entity → Table، Attribute → Column، Identifier → Primary Key.','Entity → Table, Attribute → Column, Identifier → Primary Key.'],['1:N','ضع المفتاح الأساسي من جهة الواحد كـForeign Key في جهة المتعدد.','Place the primary key from the one side as a foreign key in the many side.'],['M:N','أنشئ جدولًا جديدًا يحتوي مفاتيح الجدولين، وغالبًا يكونان مفتاحًا أساسيًا مركبًا.','Create a new table containing both table keys, often as a composite primary key.']]},
{id:'sql-basics',icon:'⌨️',ar:'أساسيات SQL',en:'SQL Basics',descAr:'تعرف على بنية الأوامر وأنواع البيانات والقيود قبل التنفيذ.',descEn:'Learn command structure, data types, and constraints before execution.',objectives:['Syntax','Data Types','Constraints'],storyAr:'SQL هي اللغة التي تستخدمها للتحدث مع قاعدة البيانات: تسألها، تضيف لها، تعدلها، أو تغيّر بنيتها.',storyEn:'SQL is the language used to communicate with a database: query, insert, update, or change its structure.',sections:[['أنواع الأوامر','DDL للبنية، DML للبيانات، DCL للصلاحيات، TCL للمعاملات، وSELECT للاستعلام.','DDL for structure, DML for data, DCL for privileges, TCL for transactions, and SELECT for queries.'],['أنواع البيانات','NUMBER للأرقام، VARCHAR2 للنص المتغير، CHAR للنص الثابت، DATE للتاريخ في Oracle.','NUMBER for numbers, VARCHAR2 for variable text, CHAR for fixed text, and DATE for Oracle dates.'],['القيود','PRIMARY KEY وFOREIGN KEY وNOT NULL وUNIQUE وCHECK وDEFAULT.','PRIMARY KEY, FOREIGN KEY, NOT NULL, UNIQUE, CHECK, and DEFAULT.']]},
{id:'ddl',icon:'🏗️',ar:'DDL — تعريف بنية البيانات',en:'DDL — Data Definition Language',descAr:'جميع أوامر إنشاء وتعديل وحذف كائنات قاعدة البيانات.',descEn:'All commands for creating, changing, and removing database objects.',objectives:['CREATE','ALTER','DROP وTRUNCATE'],storyAr:'DDL لا يغيّر صفًا واحدًا فقط؛ بل يغيّر شكل قاعدة البيانات نفسها.',storyEn:'DDL does not change only one row; it changes the database structure itself.',sections:[['الأوامر','CREATE، ALTER، DROP، TRUNCATE، RENAME، COMMENT.','CREATE, ALTER, DROP, TRUNCATE, RENAME, and COMMENT.'],['فرق مهم','DELETE يحذف صفوفًا ويمكن وضع شرط. TRUNCATE يفرغ الجدول بالكامل بسرعة ويحافظ على هيكله. DROP يحذف الكائن نفسه.','DELETE removes rows and supports conditions. TRUNCATE quickly empties the table but keeps its structure. DROP removes the object itself.'],['مثال','CREATE TABLE students (student_id NUMBER PRIMARY KEY, name VARCHAR2(50) NOT NULL);','CREATE TABLE students (student_id NUMBER PRIMARY KEY, name VARCHAR2(50) NOT NULL);']]},
{id:'dml',icon:'✍️',ar:'DML — معالجة البيانات',en:'DML — Data Manipulation Language',descAr:'أضف وعدّل واحذف وادمج السجلات بأمان.',descEn:'Insert, update, delete, and merge records safely.',objectives:['INSERT','UPDATE وDELETE','MERGE'],storyAr:'بعد إنشاء الجدول باستخدام DDL، تأتي DML للتعامل مع البيانات الموجودة بداخله.',storyEn:'After creating a table with DDL, DML handles the data inside it.',sections:[['INSERT','يضيف سجلًا أو عدة سجلات. الأفضل تحديد أسماء الأعمدة بوضوح.','Adds one or more rows. It is best to explicitly list column names.'],['UPDATE وDELETE','استخدم WHERE لتحديد السجلات. بدون WHERE قد تعدل أو تحذف جميع الصفوف.','Use WHERE to target rows. Without WHERE, all rows may be updated or deleted.'],['MERGE','يجمع INSERT وUPDATE حسب وجود السجل، ومفيد للمزامنة.','Combines INSERT and UPDATE depending on whether the row exists; useful for synchronization.']]},
{id:'dcl',icon:'🔐',ar:'DCL — التحكم بالصلاحيات',en:'DCL — Data Control Language',descAr:'امنح الصلاحيات واسحبها بطريقة صحيحة.',descEn:'Grant and revoke privileges correctly.',objectives:['System Privileges','Object Privileges','GRANT وREVOKE'],storyAr:'ليس كل مستخدم يجب أن يستطيع إنشاء الجداول أو قراءة كل البيانات. DCL تحدد من يستطيع فعل ماذا.',storyEn:'Not every user should create tables or read all data. DCL defines who can do what.',sections:[['GRANT','يمنح صلاحية نظام مثل CREATE TABLE أو صلاحية على كائن مثل SELECT ON employees.','Grants a system privilege such as CREATE TABLE or an object privilege such as SELECT ON employees.'],['REVOKE','يسحب صلاحية سبق منحها. يجب كتابة نفس نوع الصلاحية بشكل صحيح.','Removes a previously granted privilege. The correct privilege type must be specified.'],['أمثلة','GRANT CREATE SESSION TO ali; — GRANT SELECT ON employees TO ali; — REVOKE SELECT ON employees FROM ali;','GRANT CREATE SESSION TO ali; — GRANT SELECT ON employees TO ali; — REVOKE SELECT ON employees FROM ali;']]},
{id:'objects',icon:'🧰',ar:'SQL Objects',en:'SQL Objects',descAr:'تعلم Tables وViews وSequences وSynonyms وIndexes.',descEn:'Learn tables, views, sequences, synonyms, and indexes.',objectives:['Table وView','Sequence وSynonym','Index'],storyAr:'قاعدة البيانات ليست جداول فقط؛ بل تحتوي كائنات تساعد على العرض، الترقيم، التسمية، وتسريع البحث.',storyEn:'A database contains more than tables; objects help with presentation, numbering, naming, and faster search.',sections:[['Table وView','Table يخزن البيانات فعليًا. View يعرض نتيجة استعلام محفوظ ولا يخزن البيانات غالبًا بنفسه.','A table physically stores data. A view presents a saved query result and usually does not store the data itself.'],['Sequence وSynonym','Sequence يولد أرقامًا متسلسلة. Synonym يعطي اسمًا بديلًا لكائن.','A sequence generates numbers. A synonym provides an alternate name for an object.'],['Index','بنية تسرّع البحث والفرز، لكنها تستهلك مساحة وقد تبطئ عمليات التعديل الكثيرة.','A structure that speeds searching and sorting, but uses space and may slow frequent changes.']]},
{id:'joins',icon:'🔗',ar:'JOIN — INNER وCROSS',en:'JOIN — INNER and CROSS',descAr:'ادمج بيانات أكثر من جدول بطريقة مفهومة.',descEn:'Combine data from multiple tables clearly.',objectives:['INNER JOIN','CROSS JOIN','شروط الربط'],storyAr:'جدول الموظفين يحتوي Department_ID، واسم القسم موجود في جدول الأقسام. JOIN يجمعهما في نتيجة واحدة.',storyEn:'The employees table has Department_ID, while the department name is in departments. JOIN combines them in one result.',sections:[['INNER JOIN','يعرض الصفوف التي تحقق شرط الربط في الجدولين فقط.','Returns only rows matching the join condition in both tables.'],['CROSS JOIN','يعرض كل صف من الجدول الأول مع كل صف من الثاني. عدد النتائج = عدد صفوف الأول × الثاني.','Returns every row from the first table with every row from the second. Result count = first rows × second rows.'],['خطأ شائع','نسيان شرط الربط قد ينتج عددًا ضخمًا وغير مقصود من الصفوف.','Forgetting the join condition may produce a huge unintended number of rows.']]},
{id:'api-mcp',icon:'🌐',ar:'APIs وMCP',en:'APIs and MCP',descAr:'افهم كيف تتواصل الأنظمة وكيف تتصل أدوات الذكاء الاصطناعي بالخدمات.',descEn:'Understand system communication and how AI tools connect to services.',objectives:['Request/Response','REST وJSON','MCP'],storyAr:'واجهة الموقع لا تدخل قاعدة البيانات مباشرة. ترسل Request إلى API، والـAPI يعالج الطلب ويرسل Response. MCP يضع طريقة موحدة لربط نماذج الذكاء الاصطناعي بالأدوات والبيانات.',storyEn:'A frontend does not directly access the database. It sends a request to an API, which processes it and returns a response. MCP standardizes connecting AI models to tools and data.',sections:[['API','عقد يحدد كيف تطلب خدمة من خدمة أخرى. REST يستخدم HTTP وطرق GET وPOST وPUT وDELETE.','A contract defining how one service requests another. REST uses HTTP methods such as GET, POST, PUT, and DELETE.'],['Status Codes','200 نجاح، 201 إنشاء، 400 طلب غير صحيح، 401 غير مصرح، 404 غير موجود، 500 خطأ خادم.','200 success, 201 created, 400 bad request, 401 unauthorized, 404 not found, 500 server error.'],['MCP','Model Context Protocol معيار لعرض الأدوات والموارد للنماذج بطريقة منظمة وقابلة لإعادة الاستخدام.','Model Context Protocol is a standard for exposing tools and resources to models in an organized, reusable way.']]},
{id:'llm',icon:'🧠',ar:'LLM وTransformers وWeights',en:'LLMs, Transformers, and Weights',descAr:'افهم أساس النماذج اللغوية بدون رياضيات معقدة.',descEn:'Understand language models without complex mathematics.',objectives:['LLM وTokens','Transformer','Weights'],storyAr:'النموذج لا يحفظ الإجابة كجملة جاهزة؛ بل يتوقع الجزء التالي اعتمادًا على أنماط تعلمها من بيانات كثيرة.',storyEn:'A model does not store each answer as a ready sentence; it predicts the next piece based on patterns learned from large datasets.',sections:[['LLM وTokens','LLM نموذج مدرب على نصوص كثيرة. يقسم النص إلى Tokens ويتنبأ بالـToken التالي.','An LLM is trained on large amounts of text. It splits text into tokens and predicts the next token.'],['Transformer','معمارية تستخدم Attention لفهم علاقة الكلمات ببعضها حتى لو كانت بعيدة في الجملة.','An architecture using attention to understand relationships between words, even when far apart.'],['Weights','أرقام داخل النموذج تتغير أثناء التدريب. تمثل الأنماط التي تعلمها النموذج، وليست كلمات محفوظة بشكل مباشر.','Numbers inside the model adjusted during training. They represent learned patterns, not directly stored words.']]},
{id:'prompt',icon:'✨',ar:'Prompt Engineering',en:'Prompt Engineering',descAr:'اكتب تعليمات واضحة تعطي نتائج أفضل.',descEn:'Write clear instructions that produce better results.',objectives:['Goal','Context','Constraints'],storyAr:'بدل أن تقول اشرح SQL، قل: اشرح INNER JOIN بالعربية لمبتدئ، مع جدولين ومثال ونتيجة، ثم سؤال قصير.',storyEn:'Instead of “explain SQL,” say: explain INNER JOIN to a beginner, with two tables, an example, output, and a short question.',sections:[['مكونات Prompt جيد','الدور، الهدف، السياق، القيود، شكل المخرجات، ومثال عند الحاجة.','Role, goal, context, constraints, output format, and an example when needed.'],['التدرج','ابدأ بطلب واضح، راجع النتيجة، ثم حسّن التعليمات بدل كتابة طلب ضخم وغامض.','Start with a clear request, review the result, then refine instead of writing a huge vague prompt.'],['تجنب','الغموض، التناقض، عدم تحديد الجمهور، وطلب معلومات دقيقة دون توفير سياق.','Avoid ambiguity, contradictions, missing audience, and requesting precise output without context.']]},
{id:'n8n-ats-uiux',icon:'🚀',ar:'n8n وATS وUI/UX',en:'n8n, ATS, and UI/UX',descAr:'اختتم المسار بأدوات سوق العمل وتجربة المستخدم.',descEn:'Finish with workplace automation, hiring systems, and user experience.',objectives:['n8n','ATS','UI مقابل UX'],storyAr:'n8n يؤتمت سير العمل، ATS يرشح السير الذاتية، وUI/UX يجعل النظام واضحًا ومريحًا للمستخدم.',storyEn:'n8n automates workflows, ATS screens resumes, and UI/UX makes systems clear and comfortable.',sections:[['n8n','أداة Workflow تربط الخدمات باستخدام Nodes وTriggers وActions، ويمكنها دمج APIs والذكاء الاصطناعي.','A workflow tool connecting services through nodes, triggers, and actions, including APIs and AI.'],['ATS','نظام يستخدمه أصحاب العمل لتنظيم الطلبات والبحث عن المهارات والكلمات المرتبطة بالوظيفة.','A system employers use to organize applications and search for job-related skills and keywords.'],['UI/UX','UI هو الشكل والعناصر المرئية. UX هي التجربة الكاملة وسهولة الوصول للهدف. التصميم الجميل وحده لا يكفي إذا كان الاستخدام صعبًا.','UI is the visual interface. UX is the overall experience and ease of reaching a goal. Beauty alone is not enough when usage is difficult.']]}
];
